-- ── Airbase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Airbase, now operating as Airbase by Paylocity, is a spend management platform that unifies accounts payable automation, corporate cards, procurement, and expense management for mid-market companies.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California (acquired by Paylocity, headquartered in Schaumburg, Illinois, in 2024)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Airbase Review 2026: Spend Management Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Airbase review for 2026: what the spend management platform does, its 2024 acquisition by Paylocity, key features, and how it compares to Ramp and Brex.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Airbase is a spend management platform founded in May 2017 by Thejo Kote, an entrepreneur who previously co-founded the connected-car company Automatic, which was acquired by SiriusXM for 115 million dollars. Kote started Airbase after experiencing firsthand how fragmented and manual spend management was at his previous startup, and he initially bootstrapped the company with around 300,000 dollars before raising a Series A from First Round Capital in 2019 and a 60 million dollar Series B led by Menlo Ventures in June 2021 at a roughly 600 million dollar post-money valuation, ultimately raising over 90 million dollars in total funding. Airbase built a unified procure-to-pay platform combining accounts payable automation, software-enabled corporate cards, employee expense management and reimbursements, and guided procurement with purchase-order workflows, all tied together with configurable approval policies and real-time spend visibility, plus deep integrations with ERPs like NetSuite. It processed roughly 3 billion dollars in payments annually for customers such as Cameo, Finix, Front, and Getaround before a major change in ownership: on October 1, 2024, HR and payroll company Paylocity completed its acquisition of Airbase for approximately 325 million dollars. As of 2026, the product operates under the branding Airbase by Paylocity, integrated into what Paylocity markets as Paylocity for Finance, combining Airbase's non-payroll spend management with Paylocity's payroll and human capital management platform so customers can see both payroll and non-payroll spend in one system. Airbase deliberately positioned itself differently from self-serve rivals like Ramp and Brex: where Ramp and Brex historically offered free or low-cost card products monetized primarily through interchange revenue and targeted broad startup and SMB audiences, Airbase targeted mid-market companies (roughly 100 or more employees) with a paid, software-subscription-first model, with an estimated 70 to 80 percent or more of its revenue coming from SaaS subscriptions rather than card interchange. Airbase does not publish self-serve pricing; prospective customers must request a demo and receive a custom quote based on company size and modules needed. Its main competitors remain Ramp, Brex, and BILL, and its key differentiator continues to be the breadth of its unified platform (procurement, AP, cards, and expenses in one system with strong approval workflows) now paired with the reach and resources of its Paylocity parent company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '524ae882-aec6-47f8-a972-c700382a2639';

