-- ── Airware ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Airware was a commercial drone software and hardware company founded in 2011 that built an enterprise aerial data platform before shutting down in September 2018 after raising and spending 118 million dollars in venture funding.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$up to approx 140 employees at its peak, before its 2018 shutdown$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California (originally founded in Newport Beach, California)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Airware: What Happened to the Drone Startup (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$Airware is a defunct drone software company that shut down in September 2018 after raising 118 million dollars. Here is its history, product, and collapse.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Airware is a defunct company, not an active software product, and anyone researching it in 2026 should understand it as a historical case study rather than a tool currently available for purchase or use. It was founded in 2011 in Newport Beach, California, by Jonathan Downey, an MIT-trained electrical engineer and computer scientist who had previously built autonomous flight-control software for Boeing and organized an MIT student drone team. Airware relocated to San Francisco in January 2014 and grew into one of the best-funded companies in the commercial drone industry, eventually raising approximately 118 million dollars in venture capital from investors including Andreessen Horowitz, Google's GV, Kleiner Perkins, and Intel Capital, and adding former Cisco CEO John Chambers to its board. Airware's product combined autopilot hardware and on-aircraft flight-control software with a cloud-based aerial data platform, aimed at enterprise customers in industries like construction, mining, agriculture, and insurance who wanted to collect and analyze drone-captured data at scale, positioning itself as an operating system for commercial drones rather than a drone manufacturer itself. The business model shifted over time from selling autopilot hardware toward an enterprise software and data-analytics platform, but the company struggled to keep pace with the plummeting cost and rapidly improving quality of drone hardware from vertically integrated manufacturers, especially China's DJI, whose bundled flight software increasingly made third-party autopilot systems like Airware's unnecessary for many customers. After a period of declining relevance and multiple rounds of layoffs over roughly two years, Airware abruptly informed its remaining employees, at that point around 140 people, that it would cease all operations immediately, which it did on September 14, 2018. In the aftermath, Airware's assets, including some intellectual property and select team members, were acquired by Delair, a French drone manufacturer and asset-management company based in Toulouse. There is no current product, pricing, support, or company to evaluate; Airware exists today only as a well-documented example of a heavily funded hardware-and-software startup that could not survive the commoditization of its core market. This entry is included for historical accuracy and research purposes, and should not be mistaken for information about an active, purchasable tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e13176ec-5dc4-46d6-8405-aefa773736c7';

