  short_description = COALESCE($q$AISEO is an AI-powered content and SEO platform that has expanded from AI writing and paraphrasing tools into technical SEO audits and generative engine optimization tracking of brand visibility across AI chat tools like ChatGPT and Gemini.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
