-- ── AKQA ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AKQA is a global digital design, innovation, and advertising agency founded in 1994 by Ajaz Ahmed, now operating as part of WPP's AKQA Group alongside Grey, serving major brands on custom, project-based engagements rather than self-serve software.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(1994, founded_year),
  company_size = COALESCE($q$approx 6,000 employees across AKQA Group, following its 2020 merger with Grey Group$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom (global network of offices)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AKQA Review 2026: Global Digital Agency Profile$q$, seo_title),
  seo_meta_description = COALESCE($q$AKQA profile for 2026: history since 1994, WPP ownership, the AKQA Group merger with Grey, notable clients, and how its custom, project-based pricing works.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AKQA is not a self-serve software tool but a global digital design, innovation, and advertising agency, and it is important to evaluate it on those terms rather than as SaaS. It was founded in London in 1994 by Ajaz Ahmed, who created the agency at age 21 and named it after his own initials. AKQA expanded internationally in 2001 through a merger with agencies based in San Francisco, Washington D.C., and Singapore, growing from a UK digital shop into a multinational network that attracted early blue-chip clients including Virgin, Microsoft, McDonald's, BMW, and Coca-Cola. In 2012, global marketing holding company WPP acquired a majority stake in AKQA, buying out growth-equity investor General Atlantic and part of management's remaining shares, in a deal that valued the company at roughly 540 million dollars; AKQA has operated as a WPP subsidiary ever since while retaining its own brand identity. In November 2020, WPP restructured its agency portfolio by merging AKQA with Grey Group, forming AKQA Group as an umbrella organization that keeps AKQA and Grey as distinct client-facing brands under shared leadership and infrastructure; the combined organization employs roughly 6,000 people across about 50 countries. A significant leadership change occurred in October 2024, when founder Ajaz Ahmed stepped down as CEO of AKQA Group after 30 years running the company he started. Today, AKQA's client roster reportedly includes more than half of the Fortune 500's top 20 companies, spanning recent work with brands like Nike, BBC Earth, and H&amp;M, and its service lines cover experience design, product and ecommerce development, CRM and customer experience consulting, brand strategy and communications, and technology and innovation consulting, including emerging areas like AI and immersive experiences. Because AKQA is a full-service agency rather than a productized tool, it has no published pricing, plans, or tiers of the kind found on this directory for SaaS products; engagements are scoped and priced individually per client, typically as project fees or ongoing retainers negotiated with each brand based on scope, team size, and duration. This makes AKQA fundamentally different from most entries in a software directory: prospective clients contact the agency directly to discuss a brief and receive a custom proposal, rather than signing up for a subscription or self-service plan.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3e6a61cb-8d49-4bab-8df7-e193fdb5828d';

