INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Pay in 4$q$, $q$Splits eligible purchases into four equal, interest-free payments made every two weeks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Monthly installment loans$q$, $q$Longer-term financing from about three to sixty months with fixed APRs from 0 percent to 36 percent.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Affirm Card$q$, $q$A hybrid debit and BNPL card that lets cardholders choose to pay now or split eligible purchases over time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Virtual card checkout$q$, $q$Generates a one-time card number so shoppers can use Affirm at merchants without a direct integration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$No late fees$q$, $q$Affirm does not charge late fees or compound interest, though missed payments can still affect credit standing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Machine learning underwriting$q$, $q$Real-time approval decisions that weigh more than a traditional credit score to assess borrower risk.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Merchant integrations$q$, $q$Native support for Shopify, Magento, WooCommerce, BigCommerce, Salesforce Commerce Cloud, and a partnership with Amazon.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Adaptive Checkout$q$, $q$A merchant-facing tool that surfaces the most relevant Affirm payment terms for each shopper at checkout.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$No late fees are ever charged to consumers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$0 percent APR is available on many qualifying purchases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Wide merchant acceptance, including Amazon and thousands of Shopify stores$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Total repayment cost is shown transparently before purchase$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Publicly traded and regulated, which adds a layer of financial transparency$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Interest rates can reach 36 percent APR on some loans, higher than many credit card promotional rates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Missed payments can be reported to credit bureaus and affect credit scores$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Not accepted at every merchant despite the virtual card workaround$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Merchant fees of up to roughly 12.5 percent can be costly for smaller businesses$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Approval and available terms vary by purchase, so financing is not guaranteed or consistent$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Is Affirm a bank?$q$, $q$No. Affirm partners with issuing banks such as Cross River Bank, Evolve Bank and Trust, and Celtic Bank to originate its loans.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Does Affirm charge late fees?$q$, $q$No, Affirm does not charge late fees, though missed payments can still be reported and affect a borrower's credit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$What is the Affirm Card?$q$, $q$A debit card issued by Affirm that lets holders pay immediately from their bank balance or choose to pay over time on eligible purchases.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Is Affirm a public company?$q$, $q$Yes, Affirm has traded on Nasdaq under the ticker AFRM since its IPO on January 13, 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Who founded Affirm?$q$, $q$Max Levchin, the PayPal co-founder, founded Affirm in 2012 along with Nathan Gettings, Jeffrey Kaditz, and Alex Rampell.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$How does Affirm make money?$q$, $q$Affirm earns revenue from merchant transaction fees and from interest charged to consumers on interest-bearing installment loans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$How is Affirm different from Klarna and Afterpay?$q$, $q$Affirm leans more heavily on longer-term, sometimes interest-bearing installment loans, while Klarna and Afterpay have historically emphasized short, interest-free four-payment plans, though all three now offer overlapping products.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Does using Affirm affect my credit score?$q$, $q$It can. Longer-term Affirm loans may involve a credit check, and payment history can be reported to credit bureaus, which can help or hurt a score depending on repayment behavior.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Online checkout financing$q$, $q$Shoppers use Affirm to split the cost of an online purchase into manageable payments instead of paying the full price upfront.$q$, $q$Ecommerce shoppers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Merchant conversion and order value growth$q$, $q$Online retailers offer Affirm at checkout to reduce cart abandonment and increase average order value.$q$, $q$DTC brands and online marketplaces$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Large purchase financing$q$, $q$Consumers finance higher-ticket purchases like furniture, electronics, or travel using longer Affirm installment terms.$q$, $q$Consumers making high-ticket purchases$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Pay in 4$q$, $q$0% APR$q$, $q$4 biweekly payments$q$, NULL, $q$["Interest-free","No fees if paid on time","Available at checkout for eligible purchases"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Monthly Installments$q$, $q$0% to 36% APR$q$, $q$3 to 60 months$q$, NULL, $q$["Fixed monthly payments","Total cost shown upfront","No late fees, no compounding interest"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$Affirm Card$q$, $q$No annual fee$q$, $q$Pay now or over time per purchase$q$, NULL, $q$["Debit card linked to a bank account","Optional pay-over-time on eligible purchases","Works anywhere the card network is accepted"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$overview$q$, $q$What Is Affirm$q$, 2, ARRAY[$q$Affirm is a buy now pay later (BNPL) fintech company founded in 2012 by Max Levchin, the PayPal co-founder, along with Nathan Gettings, Jeffrey Kaditz, and Alex Rampell. Headquartered in San Francisco, the company lets online and in-store shoppers split purchases into installment payments at checkout instead of paying the full amount upfront or opening a traditional credit card.$q$, $q$Affirm went public on Nasdaq (ticker AFRM) on January 13, 2021, raising approximately 1.2 billion dollars in its IPO. It is one of the largest publicly traded BNPL companies, reporting tens of millions of active consumers and hundreds of thousands of active merchants as of 2026, with tens of billions of dollars processed annually.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Affirm's headline products are Pay in 4, which splits a purchase into four interest-free biweekly payments, and longer monthly installment loans that stretch from about three to sixty months with APRs ranging from 0 percent to 36 percent depending on the purchase and the borrower's approval terms.$q$, $q$Affirm does not act as a direct lender; instead it partners with issuing banks like Cross River Bank, Evolve Bank and Trust, and Celtic Bank to originate loans, and it uses machine learning underwriting to approve or decline transactions instantly. Shoppers can use Affirm at directly integrated merchants (Shopify, Amazon, Walmart historically, and thousands of other stores) or via a virtual card at retailers without a native integration. The Affirm Card extends the model to everyday debit spending with optional pay-over-time.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bda0d92d-d42a-4a92-8dc2-fe12fc9ae0b7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$For consumers, Affirm charges no application fees, no late fees, and no compounding interest; the total repayment amount is shown before the purchase is confirmed, and interest, where charged, ranges from 0 percent to 36 percent APR depending on the loan.$q$, $q$For merchants, Affirm charges a transaction fee that can reach roughly 12.5 percent of the purchase amount in exchange for higher checkout conversion, larger average order values, and instant upfront payment, since Affirm pays the merchant in full at the time of sale and assumes the repayment risk.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Branded tracking pages$q$, $q$Customizable, multi-language tracking pages hosted on the merchant's own domain.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Multi-carrier tracking$q$, $q$Aggregates real-time shipment data from more than 1,100 carriers worldwide into one dashboard.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Automated shipment notifications$q$, $q$Proactive email and SMS updates at key delivery milestones to reduce support inquiries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$AI estimated delivery dates$q$, $q$Displays predicted delivery windows on product and checkout pages before and after purchase.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Returns and exchanges center$q$, $q$Self-service returns portal with store credit, exchanges, and automated return workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Post-purchase product recommendations$q$, $q$AI-powered upsell and cross-sell suggestions shown on tracking pages and in notification emails.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Shopify and Shopify Plus integration$q$, $q$Native app with deep integration into Shopify's storefront and admin experience.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Analytics dashboard$q$, $q$Reporting on carrier performance, delivery exceptions, and shipment trends.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Free plan available for low-volume stores$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Very wide carrier coverage, over 1,100 carriers globally$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Deep, mature Shopify and Shopify Plus integration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Reduces WISMO support tickets through proactive notifications$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Modular suite lets merchants adopt tracking, returns, and personalization separately$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Costs scale quickly with shipment volume and overage fees$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Advanced features like API access and full custom branding are gated behind higher tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Enterprise pricing requires a sales conversation rather than transparent public listing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Configuring automation rules and notification templates has a learning curve$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$What does AfterShip cost?$q$, $q$AfterShip offers a free plan for low shipment volumes, then paid plans starting around 11 dollars per month, scaling up based on monthly shipment count, plus custom Enterprise pricing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Does AfterShip integrate with Shopify?$q$, $q$Yes, AfterShip has a native Shopify and Shopify Plus app for both its Tracking and Returns products.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$What carriers does AfterShip support?$q$, $q$AfterShip aggregates tracking data from more than 1,100 carriers worldwide.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Does AfterShip handle returns?$q$, $q$Yes, AfterShip Returns is a dedicated product for self-service returns, exchanges, and store credit.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Is AfterShip only for Shopify stores?$q$, $q$No, it also works with WooCommerce, Magento, BigCommerce, and custom stores via its API.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$How is AfterShip different from a carrier's own tracking page?$q$, $q$AfterShip unifies tracking data from many carriers into a single branded page on the merchant's own site, instead of sending customers to each carrier's separate site.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Does AfterShip charge per shipment?$q$, $q$Yes, plans are based on monthly shipment volume with overage fees for shipments beyond a plan's included amount.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Reducing WISMO support tickets$q$, $q$Ecommerce support teams use proactive tracking notifications to cut down on where-is-my-order inquiries.$q$, $q$Ecommerce customer support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Branded post-purchase experience$q$, $q$DTC brands keep customers on-site and on-brand throughout the shipping and delivery journey.$q$, $q$Direct-to-consumer brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Returns and exchange automation$q$, $q$Retailers with high return volume automate returns processing and recover revenue through exchanges.$q$, $q$Retailers managing high return volume$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["Up to 50 shipments per month","Basic tracking page"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Essentials$q$, $q$$11/month$q$, $q$monthly$q$, NULL, $q$["Up to 300 shipments per month","Branded tracking page","Email notifications"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Pro$q$, $q$$119/month$q$, $q$monthly$q$, NULL, $q$["Up to 2,000 shipments per month","Advanced analytics","Custom branding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Premium$q$, $q$$219/month$q$, $q$monthly$q$, NULL, $q$["Up to 3,000 shipments per month","API access","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["10,000+ shipments per month","Dedicated account manager","SLA guarantees"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$overview$q$, $q$What Is AfterShip$q$, 2, ARRAY[$q$AfterShip was founded in 2012 to solve a simple ecommerce problem: shoppers constantly asking where is my order. It started as a shipment tracking API and has since grown into a full post-purchase suite used by online retailers to manage the entire delivery and returns experience under their own brand.$q$, $q$The company, now headquartered in Singapore after starting in Hong Kong, aggregates tracking data from more than 1,100 carriers worldwide and is widely used by Shopify and Shopify Plus merchants, alongside stores on WooCommerce, Magento, and BigCommerce.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$AfterShip's flagship product is the branded tracking page, a customizable, multi-language page hosted on the merchant's own domain that shows real-time shipment status pulled from over a thousand carriers, paired with automated email and SMS delivery notifications.$q$, $q$Beyond tracking, AfterShip Returns automates the returns and exchanges process with self-service portals, store credit options, and AI-powered product recommendations designed to convert returns into exchanges. AI-estimated delivery dates can also be displayed on product and checkout pages before purchase to reduce cart abandonment caused by shipping uncertainty.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc3cb5d8-f800-4692-a2ad-71a9bdd7d007', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AfterShip uses a freemium, shipment-volume-based pricing model. A free plan covers a limited number of monthly shipments, and paid plans (Essentials, Pro, and Premium) scale up in both price and included shipment volume, with per-shipment overage fees beyond each plan's cap.$q$, $q$Enterprise customers with very high shipment volumes work directly with AfterShip's sales team for custom pricing that can include dedicated account management and service-level agreements. Annual billing is available at a discount compared to monthly billing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Non-destructive RAW batch processing$q$, $q$Applies edits and exports to large batches of RAW files without altering the original source files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Native Linux support$q$, $q$One of the few commercial RAW converters offering a fully native Linux build alongside Windows and Mac.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Noise reduction and HDR merging$q$, $q$Advanced noise reduction and HDR tools available in the Pro tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Folder-based photo management$q$, $q$Works directly against folders on disk rather than requiring a proprietary catalog database.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Third-party plugin support$q$, $q$Compatible with external tools such as the Perfect Photo Suite for extended editing capability.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Batch export and watermarking$q$, $q$Applies consistent export settings and watermarks across large sets of images at once.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$One-time perpetual license$q$, $q$Purchased once rather than billed on a recurring subscription basis.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Cross-platform availability$q$, $q$Runs on Windows, Mac, and Linux from a single product line.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$One-time purchase with no recurring subscription fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Works fully offline with no cloud dependency$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Rare native Linux support among RAW editors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Lightweight and fast for batch processing large photo shoots$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$No proprietary catalog database required, working directly against folders$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Last confirmed stable update was January 2021, so support for newer cameras is uncertain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Interface and masking tools look dated next to modern editors like Lightroom or Capture One$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$No mobile app or built-in cloud sync$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Development pace has slowed dramatically, raising doubts about long-term viability$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Limited AI-based editing tools compared to current-generation RAW software$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Is AfterShot Pro still being sold?$q$, $q$Yes, as of 2026 it remains listed for sale on the official aftershotpro.com site at 79.99 dollars for a full license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Is AfterShot Pro still being actively updated?$q$, $q$The last publicly documented stable update was version 3.7.0.446 in January 2021, so the product appears to be in a maintenance-only state with no confirmed recent development.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Is AfterShot Pro the same company as AfterShip?$q$, $q$No, they are completely unrelated. AfterShip is an ecommerce shipment tracking company, while AfterShot Pro is desktop RAW photo editing software.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$What cameras does AfterShot Pro support?$q$, $q$It supports RAW formats from major camera manufacturers as of its last confirmed update in 2021; support for camera models released after that point is not confirmed.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Does AfterShot Pro require a subscription?$q$, $q$No, it uses a one-time perpetual license model rather than a monthly or annual subscription.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$What was AfterShot Pro before Corel acquired it?$q$, $q$It began as Bibble, created by Bibble Labs (founded by Eric Hyman in 2000), before Corel acquired the company and rebranded the software.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Does AfterShot Pro work on Linux?$q$, $q$Yes, it is one of the few commercial RAW converters that offers a native Linux version alongside Windows and Mac.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Budget-conscious RAW workflow$q$, $q$Photographers who want a one-time purchase instead of an ongoing subscription for RAW processing.$q$, $q$Hobbyist and enthusiast photographers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Linux-based photo editing$q$, $q$Photographers running Linux workstations who need native RAW editing software.$q$, $q$Photographers on Linux systems$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$Legacy camera batch processing$q$, $q$Photographers with camera bodies already supported by the software's last confirmed update processing large shoots offline.$q$, $q$Photographers using established, pre-2021 camera models$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$AfterShot Pro 3 (Full License)$q$, $q$$79.99$q$, $q$one-time$q$, NULL, $q$["Non-destructive RAW batch processing","Noise reduction and HDR merging","Layers","Windows, Mac, and Linux support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$AfterShot Pro 3 (Upgrade License)$q$, $q$$59.99$q$, $q$one-time$q$, NULL, $q$["Upgrade pricing for existing AfterShot owners","Same feature set as the full license"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$overview$q$, $q$What Is AfterShot Pro$q$, 2, ARRAY[$q$AfterShot Pro traces its roots to Bibble, a RAW photo converter created in 2000 by Bibble Labs founder Eric Hyman to process files from Nikon's original D1 camera. Bibble grew into a well-regarded cross-platform RAW workflow tool before Corel Corporation acquired Bibble Labs around the end of 2011 and relaunched the product as Corel AfterShot Pro.$q$, $q$Corel (now operating under its parent company Alludo) has released three major versions since the rebrand, with AfterShot Pro 3 and its last documented update, version 3.7.0.446, dating to January 2021. It remains for sale as of 2026 but shows no confirmed recent development activity, so it is best understood as a mature product in a slow, maintenance-only phase rather than an actively evolving one. It is not related to AfterShip, the ecommerce shipment tracking company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$AfterShot Pro is built around a non-destructive, folder-based RAW workflow: instead of importing photos into a proprietary catalog database, it works directly against folders on disk, which many photographers find faster and less fragile for large shoots.$q$, $q$The Pro tier adds layers, advanced noise reduction, and HDR merging on top of the base batch processing and export tools, and the software supports third-party plugins such as the Perfect Photo Suite. Notably, it offers a native Linux build, which is uncommon among commercial RAW converters that typically limit themselves to Windows and Mac.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7584974-30ec-4e51-aaab-f7ffa033ea78', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AfterShot Pro is sold as a one-time perpetual license rather than a recurring subscription, priced at 79.99 dollars for a full new license, with a lower upgrade price of around 59.99 dollars for existing owners moving to a newer version.$q$, $q$A free, fully functional 30-day trial is available before purchase. Because there is no subscription, buyers pay once and can keep using the version they purchased indefinitely, though they will not receive new features or camera compatibility updates without buying a future paid upgrade, if one is ever released.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Permanent free tier$q$, $q$1,000 emails per month free indefinitely, with no credit card required to start.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$EU-based infrastructure$q$, $q$Geo-redundant sending infrastructure located in the European Union for GDPR-aligned data residency.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Dedicated IP addresses$q$, $q$Available on paid plans to give senders more control over their sending reputation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Subaccounts$q$, $q$Isolated sending environments within one parent account, useful for agencies and SaaS platforms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Full management API$q$, $q$Programmatic control over domains, sending, and account configuration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$SMTP relay and REST API$q$, $q$Supports both traditional SMTP integration and a modern REST API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Configurable message retention$q$, $q$Retention windows for delivery logs scale from a few days up to 30 days by plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$OIDC single sign-on$q$, $q$Available on the highest tier for teams needing centralized authentication.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Permanent free tier rather than a time-limited trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Transparent, low per-1,000-email overage pricing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$EU-native infrastructure appeals to privacy-conscious teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Subaccount support useful for agencies and platforms managing multiple senders$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Simple, developer-first API and documentation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Very small, young company (founded 2023), so its long-term track record is limited$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Fewer marketing-email features since it is transactional-only by design$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Smaller ecosystem of integrations and SDKs compared to SendGrid or Mailgun$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$EU-only infrastructure may add latency for senders targeting other regions primarily$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Pricing for the top Max tier is not fully transparent on the public pricing page$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$What is AhaSend?$q$, $q$AhaSend is a pay-as-you-go transactional email API and SMTP relay service built on EU-based infrastructure.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Is there a free plan?$q$, $q$Yes, AhaSend offers 1,000 emails per month free indefinitely, with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$How does AhaSend pricing work?$q$, $q$It is pay-as-you-go, with paid plans starting around 10 dollars per month for 25,000 emails and roughly 0.50 dollars per 1,000 additional emails, with tiered discounts at higher volumes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Where is AhaSend's infrastructure located?$q$, $q$AhaSend runs geo-redundant infrastructure based in the European Union.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Who is behind AhaSend?$q$, $q$AhaSend is built by AH Technology, a company founded in 2023 and headquartered in Amsterdam, Netherlands.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$How does AhaSend compare to SendGrid or Resend?$q$, $q$AhaSend offers lower entry-level pricing, a permanent free tier, and EU data residency, but it is a much smaller and younger company than established providers like SendGrid.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Does AhaSend support dedicated IPs?$q$, $q$Yes, dedicated IP addresses are available starting on the paid Pro tier.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Transactional email for SaaS apps$q$, $q$Developers send password resets, receipts, and account notifications through AhaSend's API.$q$, $q$Software developers and SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Agencies managing multiple client sending domains$q$, $q$Agencies use subaccounts to isolate sending environments for different clients under one AhaSend account.$q$, $q$Digital agencies and platform builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$EU-based data residency requirements$q$, $q$European companies use AhaSend's EU-native infrastructure to align with GDPR expectations.$q$, $q$European startups and businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["1,000 emails per month","Community support","Full management API"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Pro$q$, $q$$10/month$q$, $q$monthly$q$, NULL, $q$["25,000 emails per month","Dedicated IPs","7-day support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$Max$q$, $q$Custom (higher-volume tier)$q$, $q$monthly$q$, NULL, $q$["100,000 emails per month","Premium support","OIDC single sign-on"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$overview$q$, $q$What Is AhaSend$q$, 2, ARRAY[$q$AhaSend is a transactional email API and SMTP relay service built by AH Technology, founded in 2023 and headquartered in Amsterdam, Netherlands. The product grew out of in-house email infrastructure the founding team built after struggling with delivery delays from other providers, later spun out as a standalone commercial service.$q$, $q$AhaSend focuses exclusively on transactional email, such as password resets, receipts, and account notifications, rather than marketing email, and it runs on EU-based infrastructure built on the KumoMTA mail transfer agent.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform provides a full management API and SMTP relay, subaccounts for agencies and platforms managing multiple senders, and dedicated IP addresses on paid tiers. Retention of message and delivery logs scales with plan level, from a few days on the free tier up to 30 days on higher tiers.$q$, $q$Because its infrastructure is EU-based, AhaSend appeals to companies that need GDPR-aligned data residency without routing email through US servers, and higher tiers add OIDC single sign-on and premium support for larger teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e4e497c-9116-4d93-8c45-5cda0f2031d0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AhaSend offers a permanent free tier of 1,000 emails per month with no credit card required, followed by pay-as-you-go paid plans starting around 10 dollars per month for roughly 25,000 emails, with extra usage billed at about 0.50 dollars per 1,000 emails and volume discounts as usage scales.$q$, $q$Higher tiers, referred to as Pro and Max, add dedicated IPs, longer retention windows, and premium support, though the exact price of the top Max tier is not publicly listed and requires contacting AhaSend directly.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Accounts payable automation$q$, $q$Automates bill capture, approval routing, and payment for non-payroll spend.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Software-enabled corporate cards$q$, $q$Issues physical and virtual cards with policy-based spend controls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Guided procurement$q$, $q$Purchase-order workflows that route buying requests through configurable approval chains.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Employee expense management$q$, $q$Handles expense report submission, approval, and reimbursement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Real-time budgeting and visibility$q$, $q$Dashboards showing live spend against budget across departments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$ERP integrations$q$, $q$Deep integration with accounting and ERP systems including NetSuite.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Configurable approval workflows$q$, $q$Approval routing customizable by department, spend category, and dollar threshold.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Combined payroll and non-payroll visibility$q$, $q$Following the Paylocity acquisition, Airbase spend data can be viewed alongside payroll data in one system.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Combines multiple spend categories, accounts payable, cards, procurement, and expenses, in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Strong ERP integrations, especially with NetSuite$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Now offers combined payroll and non-payroll visibility through Paylocity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Built for mid-market complexity with granular approval workflows and guided procurement$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Established track record, having processed roughly 3 billion dollars annually before the acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$No transparent public pricing, requiring a sales demo and custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Now part of Paylocity, so its product roadmap is tied to a larger HCM company rather than an independent focus$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Historically positioned above simpler self-serve competitors like Ramp and Brex in price and setup complexity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Customer support and product experience may shift during the ongoing Paylocity integration$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Reduced standalone brand visibility since the 2024 acquisition$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Is Airbase still available?$q$, $q$Yes, it operates as Airbase by Paylocity following Paylocity's acquisition of the company, which closed October 1, 2024.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Who founded Airbase?$q$, $q$Thejo Kote founded Airbase in May 2017 after previously co-founding and selling the connected-car startup Automatic to SiriusXM.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$How much does Airbase cost?$q$, $q$Pricing is custom and quote-based; Airbase does not publish self-serve pricing tiers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$How is Airbase different from Ramp and Brex?$q$, $q$Airbase targets mid-market companies with a software-subscription-first model and guided procurement, while Ramp and Brex have historically emphasized free, self-serve access monetized largely through card interchange.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$What happened with the Paylocity acquisition?$q$, $q$Paylocity acquired Airbase for approximately 325 million dollars, with the deal completing on October 1, 2024.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Does Airbase integrate with NetSuite?$q$, $q$Yes, Airbase has a dedicated integration with NetSuite and other ERP systems.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$What is Paylocity for Finance?$q$, $q$It is the combined branding under which Airbase's spend management capabilities are integrated into Paylocity's payroll and HCM platform.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Procure-to-pay automation$q$, $q$Finance teams automate purchase requests, approvals, and vendor bill payments in one workflow.$q$, $q$Controllers and finance teams at mid-market companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Corporate card spend control$q$, $q$Finance teams issue policy-controlled cards to employees and departments to prevent overspending.$q$, $q$Finance teams needing granular card controls$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$Unified payroll and non-payroll spend visibility$q$, $q$Companies already using Paylocity for HR and payroll add Airbase to see all company spend in one place.$q$, $q$Paylocity customers expanding into spend management$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$overview$q$, $q$What Is Airbase$q$, 2, ARRAY[$q$Airbase is a spend management platform founded in May 2017 by Thejo Kote, who previously built and sold the connected-car startup Automatic to SiriusXM. Airbase combines accounts payable automation, corporate cards, employee expense management, and guided procurement into a single system built for mid-market companies.$q$, $q$After bootstrapping the company and later raising a Series A from First Round Capital and a Series B led by Menlo Ventures, Airbase was acquired by HR and payroll company Paylocity in a deal that closed October 1, 2024 for roughly 325 million dollars. It now operates as Airbase by Paylocity.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Airbase's platform centers on accounts payable automation and bill pay, software-enabled corporate cards with configurable spend controls, and guided procurement with purchase-order workflows, all governed by approval policies that can be customized by department and spend category.$q$, $q$It also includes employee expense management and reimbursements, real-time budgeting and spend dashboards, and deep integrations with ERP systems such as NetSuite. Since the Paylocity acquisition, Airbase capabilities are increasingly bundled with Paylocity's payroll and HCM platform under the Paylocity for Finance branding, giving customers combined visibility into payroll and non-payroll spend.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('524ae882-aec6-47f8-a972-c700382a2639', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Airbase does not publish self-serve pricing tiers. Historically, its revenue model combined SaaS subscription fees (an estimated 70 to 80 percent or more of revenue) with corporate card interchange revenue, differentiating it from competitors that leaned more heavily on free, interchange-funded products.$q$, $q$Prospective customers must request a demo and receive a custom quote based on company size, transaction volume, and which modules (AP, cards, procurement, expenses) they need, a structure that has continued following the Paylocity acquisition.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Enterprise drone operating system (historical)$q$, $q$Combined flight-control hardware and software marketed as an operating system for commercial drones.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Aerial data analytics platform (historical)$q$, $q$Cloud-based processing and analysis of drone-captured data for industries like construction, mining, and agriculture.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Autopilot hardware and flight-control software (historical)$q$, $q$Original core product providing autopilot systems for third-party drone airframes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Enterprise partnerships (historical)$q$, $q$Worked with commercial drone manufacturers and large enterprise customers on aerial data programs.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Was an early, well-funded leader in enterprise drone software during 2011 to 2018$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Attracted top-tier investors including Andreessen Horowitz, GV, and Kleiner Perkins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Backed by an experienced founder with an MIT engineering and Boeing flight-software background$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Ceased all operations on September 14, 2018 and no longer offers any product or support$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Burned through approximately 118 million dollars in venture funding before shutting down$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Lost ground to lower-cost, vertically integrated drone hardware makers like DJI$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Any current references to Airware describe a defunct company, not an active tool$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Is Airware still in business?$q$, $q$No, Airware ceased all operations on September 14, 2018.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$What happened to Airware?$q$, $q$It ran out of funding after struggling to compete against cheaper, vertically integrated drone hardware from companies like DJI, and was forced to shut down.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Who founded Airware?$q$, $q$Jonathan Downey founded Airware in 2011 in Newport Beach, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$How much funding did Airware raise?$q$, $q$Approximately 118 million dollars from investors including Andreessen Horowitz, GV, and Kleiner Perkins.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$What happened to Airware's assets and team?$q$, $q$Delair, a French drone and asset-management company, acquired Airware's assets and some team members in 2018.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Can I still buy or use Airware software?$q$, $q$No, the product is no longer sold, supported, or maintained by any company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Enterprise aerial data collection (historical)$q$, $q$Construction, mining, and agriculture companies used Airware's platform to collect and analyze drone-captured data between 2011 and 2018.$q$, $q$Construction and mining companies (historical, no longer available)$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Drone autopilot systems (historical)$q$, $q$Commercial drone operators used Airware's autopilot hardware and flight-control software before its 2018 shutdown.$q$, $q$Commercial drone operators (historical, no longer available)$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$Startup case study$q$, $q$Airware is frequently studied as an example of a heavily funded hardware-software startup that failed due to market commoditization.$q$, $q$Startup founders and investors studying market history$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$overview$q$, $q$What Airware Was$q$, 2, ARRAY[$q$Airware was a commercial drone software and hardware company founded in 2011 in Newport Beach, California, by Jonathan Downey, and later relocated to San Francisco in January 2014. It built autopilot systems and an enterprise aerial data platform aimed at industries like construction, mining, and agriculture.$q$, $q$The company raised approximately 118 million dollars in venture funding from investors including Andreessen Horowitz, GV, Kleiner Perkins, and Intel Capital, and it was widely regarded as one of the best-capitalized companies in the early commercial drone industry.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$why-it-shut-down$q$, $q$Why Airware Shut Down$q$, 2, ARRAY[$q$Airware's business model shifted over time from selling proprietary autopilot hardware toward enterprise aerial-data software, but it struggled to compete as drone hardware makers, particularly China's DJI, drove down costs and improved bundled flight software to the point where third-party autopilot systems became less necessary for many customers.$q$, $q$After roughly two years of declining relevance and repeated layoffs, Airware ceased all operations on September 14, 2018, informing its remaining approximately 140 employees the business was shutting down immediately. Its assets were later acquired by Delair, a French drone and asset-management company.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e13176ec-5dc4-46d6-8405-aefa773736c7', $q$current-status$q$, $q$Current Status$q$, 2, ARRAY[$q$Airware no longer exists as an operating company, and it has no current product, pricing, or support available. Anyone encountering the Airware name today, including on its former website, should treat it as a historical reference rather than an active software tool.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$SEO Agent$q$, $q$Crawls a website daily and flags more than 50 potential ranking issues, prioritized by impact.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Brand Monitor$q$, $q$Tracks brand mentions and visibility inside AI-generated answers from tools like ChatGPT, Gemini, Claude, Copilot, and Perplexity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Reddit Agent$q$, $q$Monitors brand mentions in Reddit threads that rank on Google search results.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$AI Article Generator and Longform Assistant$q$, $q$Generates SEO-oriented blog posts and longer-form content from a topic or outline.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$AI Humanizer$q$, $q$Rewrites AI-generated text to read more naturally, marketed as helping it pass AI-detection tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Advanced Paraphraser$q$, $q$Adjusts tone and fluency of existing text for different audiences or purposes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Keyword and backlink research$q$, $q$Includes keyword research and competitor backlink analysis tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Automatic schema markup and image generation$q$, $q$Generates structured data markup and accompanying images for published content.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Combines traditional SEO tooling with newer AI-search (GEO) visibility tracking in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Supports multiple languages for content generation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Offers both content creation and technical SEO auditing in a single subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Actively evolving to keep pace with AI search trends$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Lower entry price point than many enterprise SEO suites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Pricing and plan structure have shifted noticeably across the product's history$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$AI-generated content still needs human review for accuracy and originality$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Marketing around bypassing AI-detection tools raises academic and editorial integrity concerns for some use cases$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Limited public information on team size and funding compared to larger competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Broad feature set (SEO plus GEO plus writing) may mean less depth than single-purpose specialist tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$What does AISEO do?$q$, $q$It combines AI content generation with technical SEO auditing and AI-search (GEO) brand visibility tracking across tools like ChatGPT and Gemini.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$How much does AISEO cost?$q$, $q$Current published pricing starts around 39 dollars per month for the Entry plan, with a Pro plan around 119 dollars per month, though pricing has changed over time and should be confirmed on aiseo.ai.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Is there a free trial?$q$, $q$AISEO typically offers a short, low-cost trial period, often around 1 dollar for the first billing period, before regular pricing applies.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$What is GEO tracking in AISEO?$q$, $q$It monitors how often and how favorably a brand is mentioned in AI-generated answers from tools like ChatGPT, Gemini, and Claude.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Can AISEO help bypass AI content detectors?$q$, $q$The company markets an AI Humanizer feature intended to make generated text read as more human-written, though effectiveness against detection tools can vary.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Who founded AISEO?$q$, $q$The company was founded in 2021 and is headquartered in Amsterdam, Netherlands.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Does AISEO replace a dedicated SEO tool like Ahrefs or Semrush?$q$, $q$It offers overlapping features such as keyword research and backlink analysis, but it is not as specialized or deep as dedicated SEO suites.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$AI search visibility monitoring$q$, $q$Marketing teams track how their brand is mentioned or recommended across ChatGPT, Gemini, and other AI assistants.$q$, $q$Marketing teams tracking AI-search visibility$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$SEO content production at scale$q$, $q$Bloggers and agencies generate SEO-oriented articles and blog posts quickly using AI drafting tools.$q$, $q$Bloggers, agencies, and content marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Technical SEO auditing$q$, $q$Small business owners without a dedicated SEO specialist use the SEO Agent to find and prioritize ranking issues.$q$, $q$Small business owners and solo marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Entry$q$, $q$$39/month (after a low-cost trial period)$q$, $q$monthly$q$, NULL, $q$["1 website tracked","1 brand monitored","Basic SEO issue detection","Support for OpenAI, Claude, Gemini, and Copilot tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$Pro$q$, $q$$119/month (after a low-cost trial period)$q$, $q$monthly$q$, NULL, $q$["3 websites tracked","3 brands monitored","Full SEO Agent audits","Competitor tracking and backlinks analysis","Monthly AI credit allowance"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$overview$q$, $q$What Is AISEO$q$, 2, ARRAY[$q$AISEO is a content and search optimization platform from a company founded in 2021 and headquartered in Amsterdam, Netherlands. It started as an AI writing and paraphrasing tool for SEO-friendly blog content and has since expanded into technical SEO auditing and AI-search visibility tracking.$q$, $q$The platform now spans three overlapping areas: AI content generation, traditional on-site SEO auditing, and generative engine optimization (GEO), which monitors how a brand appears in answers from AI chat tools like ChatGPT and Gemini.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The SEO Agent crawls a website daily and surfaces more than 50 potential ranking issues prioritized by likely impact, while the Brand Monitor tracks brand mentions and sentiment inside AI-generated answers across major AI assistants, and the Reddit Agent watches brand mentions in Reddit threads that rank in Google search results.$q$, $q$On the content side, AISEO offers a Longform Assistant, an AI Article Generator, an advanced paraphraser, an AI humanizer, keyword research, competitor and backlink analysis, and automatic schema markup and image generation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9d2d9200-cb3b-477c-8688-3bf69c524630', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AISEO's most recent official pricing shows an Entry plan around 39 dollars per month, typically preceded by a short, low-cost trial period, covering one tracked website and one monitored brand with basic SEO issue detection. A Pro plan around 119 dollars per month covers three websites and three brands with a fuller SEO Agent, competitor tracking, backlinks analysis, and a monthly AI credit allowance.$q$, $q$AISEO's pricing structure has changed noticeably across different points in the company's history, moving from word-count-based content generation credits toward a model built more around websites tracked and brands monitored, so buyers should confirm current pricing directly on aiseo.ai before committing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Digital product design and development$q$, $q$End-to-end design and engineering of digital products for enterprise clients.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Ecommerce experience design$q$, $q$Design and build of ecommerce platforms and shopping experiences for major brands.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Brand strategy and communications$q$, $q$Advertising campaigns and brand strategy work alongside digital execution.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$CRM and customer experience consulting$q$, $q$Consulting on customer relationship management and experience strategy.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Technology and platform engineering$q$, $q$Custom technology builds and platform engineering for large-scale client needs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Innovation and emerging-technology labs$q$, $q$Exploratory work in areas like AI and immersive experiences for client brands.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Global office network$q$, $q$Offices across the Americas, Europe, and Asia Pacific supporting multinational clients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Integrated work under AKQA Group$q$, $q$Collaborates with sister agency Grey under the shared AKQA Group umbrella within WPP.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Three decades of experience working with major global brands$q$, 0);
