INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Backing and resources of WPP, one of the world's largest marketing holding companies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Broad service range spanning design, technology, and communications in a single engagement$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Long list of blue-chip clients including many Fortune 500 companies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Not a self-serve product, so there is no published pricing or fixed plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Project-based engagements typically require significant budget, out of reach for small businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Ownership and leadership structure have changed multiple times, including the 2012 WPP acquisition, the 2020 Grey merger, and the founder's 2024 departure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Onboarding and engagement timelines are longer than adopting a SaaS tool$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Client experience can vary by office and by the specific team assigned to an account$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Is AKQA a software product?$q$, $q$No, it is a digital design and advertising agency offering project-based services, not a SaaS tool.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Who founded AKQA?$q$, $q$Ajaz Ahmed founded AKQA in London in 1994, at age 21.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Is AKQA an independent company?$q$, $q$No, WPP acquired a majority stake in 2012, and AKQA now operates within WPP's AKQA Group.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$What services does AKQA offer?$q$, $q$Digital product design, ecommerce development, CRM consulting, brand strategy and communications, and technology and innovation consulting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$How much does AKQA cost?$q$, $q$Pricing is custom and project-based, negotiated per client engagement, with no published rate card.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$What is AKQA Group?$q$, $q$The combined organization formed in November 2020 when WPP merged AKQA with Grey Group, keeping both as distinct client-facing brands.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Did AKQA's founder leave the company?$q$, $q$Yes, Ajaz Ahmed stepped down as CEO of AKQA Group in October 2024 after 30 years leading the agency.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Enterprise digital transformation$q$, $q$Large brands hire AKQA for end-to-end digital product design and build projects.$q$, $q$Large brands needing full-scale digital product work$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Global brand and ecommerce experience design$q$, $q$Marketing and ecommerce teams at major companies engage AKQA for brand and shopping experience design.$q$, $q$Fortune 500 marketing and ecommerce teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$Innovation and emerging technology consulting$q$, $q$Enterprises work with AKQA's innovation labs to explore AI and immersive experience concepts.$q$, $q$Enterprises exploring AI and immersive technology$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$overview$q$, $q$What Is AKQA$q$, 2, ARRAY[$q$AKQA is a global digital design and advertising agency founded in London in 1994 by Ajaz Ahmed, who named the company after his own initials at age 21. It expanded internationally in 2001 through a merger with agencies in San Francisco, Washington D.C., and Singapore, growing into a multinational network serving major global brands.$q$, $q$AKQA is not a self-serve software product. It is a service business that WPP, one of the world's largest marketing holding companies, acquired a majority stake in during 2012, and later merged with Grey Group in November 2020 to form AKQA Group, an umbrella organization employing roughly 6,000 people worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$key-features$q$, $q$Agency Capabilities$q$, 2, ARRAY[$q$AKQA's service lines span digital product design and development, ecommerce experience design and build, CRM and customer experience consulting, brand strategy and communications campaigns, and broader technology and platform engineering work for enterprise clients.$q$, $q$The agency also runs innovation and emerging-technology labs exploring areas like AI and immersive experiences, and it works with a client roster that reportedly includes more than half of the Fortune 500's top 20 companies, alongside brands such as Nike, BBC Earth, and H&amp;M.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e6a61cb-8d49-4bab-8df7-e193fdb5828d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$AKQA does not publish pricing plans or tiers because it operates as a project-based and retainer-based agency rather than a productized software tool. Each engagement is scoped and priced individually based on the client's brief, required team size, and project duration.$q$, $q$Prospective clients typically contact AKQA directly to discuss a project or retainer and receive a custom proposal, a structure common among large creative and consulting agencies but very different from the self-serve pricing found on most SaaS tools in this directory.$q$]::text[], 2);
